1	package cmd
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"io"
8		"os"
9		"path/filepath"
10		"strings"
11		"time"
12	
13		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
14		"github.com/spf13/cobra"
15	)
16	
17	// ddxManagedPaths are the only paths (relative to git root) that ddx sync is
18	// allowed to stash, stage, and commit. Nothing outside this list is ever touched.
19	var ddxManagedPaths = []string{
20		".ddx/beads.jsonl",
21		".ddx/executions",
22		".ddx/plugins",
23	}
24	
25	// SyncFailure is persisted to .ddx/sync-failure.json when sync aborts so that
26	// 'ddx doctor' can surface it without the user having to remember to check.
27	type SyncFailure struct {
28		Timestamp time.Time `json:"timestamp"`
29		Reason    string    `json:"reason"`
30	}
31	
32	// syncGitRunner is the function type used to invoke git commands in sync operations.
33	// Extracted for testability — production code uses realSyncGitRun; tests inject fakes.
34	type syncGitRunner func(ctx context.Context, dir string, args ...string) ([]byte, error)
35	
36	// realSyncGitRun runs a real git command via the standard gitpkg.Command wrapper.
37	func realSyncGitRun(ctx context.Context, dir string, args ...string) ([]byte, error) {
38		return gitpkg.Command(ctx, dir, args...).CombinedOutput()
39	}
40	
41	// checkSyncFailure reads the sync-failure.json at failurePath and returns a
42	// DiagnosticIssue if a recorded failure is found. Returns nil when the path
43	// does not exist or is unreadable.
44	func checkSyncFailure(failurePath string) *DiagnosticIssue {
45		data, err := os.ReadFile(failurePath)
46		if err != nil {
47			return nil
48		}
49		var failure SyncFailure
50		if err := json.Unmarshal(data, &failure); err != nil {
51			return nil
52		}
53		return &DiagnosticIssue{
54			Type: "sync_aborted",
55			Description: fmt.Sprintf("sync aborted at %s: %s",
56				failure.Timestamp.Format(time.RFC3339), failure.Reason),
57			Remediation: []string{
58				"Resolve the issue manually, then run 'ddx sync'",
59				fmt.Sprintf("To clear this warning without syncing: rm %s", failurePath),
60			},
61		}
62	}
