64	func (f *CommandFactory) newSyncCommand() *cobra.Command {
65		var watchMode bool
66		var interval time.Duration
67	
68		cmd := &cobra.Command{
69			Use:   "sync",
70			Short: "Synchronize DDx-managed files with origin",
71			Long: `Synchronize DDx-managed files with origin/main.
72	
73	The canonical sync flow:
74	  1. git fetch origin
75	  2. stash DDx-managed dirty files (.ddx/beads.jsonl, executions/, plugins/)
76	  3. git merge origin/main  (no rebase — preserves execute-bead history)
77	  4. git stash pop
78	  5. commit DDx-managed files with structured messages:
79	       .ddx/beads.jsonl  → "chore: tracker"
80	       .ddx/executions/  → "chore: add execution evidence"
81	  6. git push origin main  (retries once on non-fast-forward)
82	
83	Sync never touches files outside the DDx-managed allowlist. Non-DDx dirty
84	files survive unchanged.
85	
86	On abort (stash-pop conflict, double push failure), a failure record is
87	written to .ddx/sync-failure.json. Run 'ddx doctor' to surface it.`,
88			RunE: func(cmd *cobra.Command, args []string) error {
89				runner := f.syncGitRunnerOverride
90				if runner == nil {
91					runner = realSyncGitRun
92				}
93				return f.runSync(cmd, runner, watchMode, interval)
94			},
95		}
96		cmd.Flags().BoolVar(&watchMode, "watch", false, "Run sync on an interval until killed")
97		cmd.Flags().DurationVar(&interval, "interval", 15*time.Minute, "Interval between syncs (requires --watch)")
98		return cmd
99	}
100	
101	func (f *CommandFactory) runSync(cmd *cobra.Command, runner syncGitRunner, watch bool, interval time.Duration) error {
102		repoRoot := gitpkg.FindProjectRoot(f.WorkingDir)
103		ddxWorkspace := gitpkg.FindNearestDDxWorkspace(f.WorkingDir)
104		if ddxWorkspace == "" {
105			return fmt.Errorf("sync: no .ddx workspace found; run 'ddx init' first")
106		}
107	
108		s := &syncer{
109			repoRoot: repoRoot,
110			ddxDir:   filepath.Join(ddxWorkspace, ".ddx"),
111			runner:   runner,
112			out:      cmd.OutOrStdout(),
113		}
114	
115		if !watch {
116			return s.run(cmd.Context())
117		}
118	
119		fmt.Fprintf(s.out, "sync: watching (interval %s, Ctrl-C to stop)\n", interval)
120		if err := s.run(cmd.Context()); err != nil {
121			fmt.Fprintf(cmd.ErrOrStderr(), "sync: %v\n", err)
122		}
123		ticker := time.NewTicker(interval)
124		defer ticker.Stop()
125		for {
126			select {
127			case <-cmd.Context().Done():
128				return nil
129			case <-ticker.C:
130				if err := s.run(cmd.Context()); err != nil {
131					fmt.Fprintf(cmd.ErrOrStderr(), "sync: %v\n", err)
132				}
133			}
134		}
135	}
