137	// syncer holds the state for a single sync session.
138	type syncer struct {
139		repoRoot string
140		ddxDir   string
141		runner   syncGitRunner
142		out      io.Writer
143	}
144	
145	func (s *syncer) git(ctx context.Context, args ...string) ([]byte, error) {
146		return s.runner(ctx, s.repoRoot, args...)
147	}
148	
149	func (s *syncer) writeFailure(reason string) error {
150		failure := SyncFailure{Timestamp: time.Now().UTC(), Reason: reason}
151		data, _ := json.Marshal(failure)
152		_ = os.MkdirAll(s.ddxDir, 0o755)
153		_ = os.WriteFile(filepath.Join(s.ddxDir, "sync-failure.json"), data, 0o644)
154		return fmt.Errorf("sync aborted: %s", reason)
155	}
156	
157	func (s *syncer) run(ctx context.Context) error {
158		return s.runOnce(ctx, false)
159	}
160	
161	func (s *syncer) runOnce(ctx context.Context, isRetry bool) error {
162		// a. git fetch origin
163		fmt.Fprintln(s.out, "sync: fetching origin...")
164		if _, err := s.git(ctx, "fetch", "origin"); err != nil {
165			return s.writeFailure(fmt.Sprintf("fetch failed: %v", err))
166		}
167	
168		// b. stash DDx-managed dirty tracked files
169		stashed, err := s.stashDDxPaths(ctx)
170		if err != nil {
171			return s.writeFailure(fmt.Sprintf("stash failed: %v", err))
172		}
173	
174		// c. git merge origin/main (no rebase — preserves execute-bead history)
175		fmt.Fprintln(s.out, "sync: merging origin/main...")
176		if out, err := s.git(ctx, "merge", "origin/main"); err != nil {
177			if stashed {
178				_, _ = s.git(ctx, "stash", "pop")
179			}
180			return s.writeFailure(fmt.Sprintf("merge failed: %s", strings.TrimSpace(string(out))))
181		}
182	
183		// d. git stash pop
184		if stashed {
185			fmt.Fprintln(s.out, "sync: applying stashed changes...")
186			if out, err := s.git(ctx, "stash", "pop"); err != nil {
187				return s.writeFailure(fmt.Sprintf("stash-pop conflict: resolve manually then run 'git stash pop' (%s)",
188					strings.TrimSpace(string(out))))
189			}
190		}
191	
192		// e. commit DDx-managed dirty paths with structured messages
193		if err := s.commitDDxPaths(ctx); err != nil {
194			return s.writeFailure(fmt.Sprintf("commit failed: %v", err))
195		}
196	
197		// f. git push origin main; retry once on non-fast-forward
198		fmt.Fprintln(s.out, "sync: pushing to origin...")
199		pushOut, pushErr := s.git(ctx, "push", "origin", "main")
200		if pushErr != nil {
201			pushMsg := string(pushOut)
202			if isRetry {
203				return s.writeFailure(fmt.Sprintf("push failed twice: %s", strings.TrimSpace(pushMsg)))
204			}
205			if strings.Contains(pushMsg, "non-fast-forward") || strings.Contains(pushMsg, "rejected") {
206				fmt.Fprintln(s.out, "sync: push rejected (non-fast-forward), retrying from fetch...")
207				return s.runOnce(ctx, true)
208			}
209			return s.writeFailure(fmt.Sprintf("push failed: %s", strings.TrimSpace(pushMsg)))
210		}
211	
212		// Clear any existing failure marker on success.
213		_ = os.Remove(filepath.Join(s.ddxDir, "sync-failure.json"))
214		fmt.Fprintln(s.out, "sync: done")
215		return nil
216	}
