218	// stashDDxPaths stashes tracked dirty files in the DDx-managed allowlist.
219	// Returns true if a stash was created, false if there was nothing to stash.
220	// Untracked files (new execution artifacts) are not stashed; git merge
221	// does not affect them.
222	func (s *syncer) stashDDxPaths(ctx context.Context) (bool, error) {
223		// Check for tracked dirty DDx paths (ignore untracked lines starting with "??").
224		checkArgs := append([]string{"status", "--porcelain", "--"}, ddxManagedPaths...)
225		out, err := s.git(ctx, checkArgs...)
226		if err != nil {
227			return false, fmt.Errorf("status check failed: %v", err)
228		}
229		hasTrackedDirty := false
230		for _, line := range strings.Split(string(out), "\n") {
231			if line == "" || strings.HasPrefix(line, "??") {
232				continue
233			}
234			hasTrackedDirty = true
235			break
236		}
237		if !hasTrackedDirty {
238			return false, nil
239		}
240	
241		stashArgs := append([]string{"stash", "push", "--"}, ddxManagedPaths...)
242		if _, err := s.git(ctx, stashArgs...); err != nil {
243			return false, fmt.Errorf("stash push failed: %v", err)
244		}
245		return true, nil
246	}
247	
248	// commitDDxPaths stages and commits DDx-managed paths with structured messages.
249	// Commits only what is dirty; no-ops if a path group is clean.
250	func (s *syncer) commitDDxPaths(ctx context.Context) error {
251		if err := s.commitIfDirty(ctx, []string{".ddx/beads.jsonl"}, "chore: tracker"); err != nil {
252			return err
253		}
254		if err := s.commitIfDirty(ctx, []string{".ddx/executions", ".ddx/plugins"}, "chore: add execution evidence"); err != nil {
255			return err
256		}
257		return nil
258	}
259	
260	// commitIfDirty stages the given paths and commits them with message if they
261	// have any changes (staged, modified, or untracked). A no-op when clean.
262	func (s *syncer) commitIfDirty(ctx context.Context, paths []string, message string) error {
263		checkArgs := append([]string{"status", "--porcelain", "--"}, paths...)
264		out, err := s.git(ctx, checkArgs...)
265		if err != nil {
266			return fmt.Errorf("status check failed: %v", err)
267		}
268		if strings.TrimSpace(string(out)) == "" {
269			return nil
270		}
271	
272		addArgs := append([]string{"add", "--"}, paths...)
273		if _, err := s.git(ctx, addArgs...); err != nil {
274			return fmt.Errorf("git add failed: %v", err)
275		}
276	
277		if _, err := s.git(ctx, "commit", "-m", message); err != nil {
278			return fmt.Errorf("commit failed: %v", err)
279		}
280		return nil
281	}
